def solve(grid):
    import numpy as np
    from scipy.ndimage import median_filter
    from collections import deque

    grid = np.array(grid)
    H, W = grid.shape

    # Step 1: Find defects
    filtered = median_filter(grid, size=3)
    candidates = grid != filtered

    # Initial defects: candidates with <=1 same-color cardinal neighbor
    initial = np.zeros_like(grid, dtype=bool)
    for r in range(H):
        for c in range(W):
            if not candidates[r, c]:
                continue
            v = grid[r, c]
            same_count = 0
            for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                nr, nc = r+dr, c+dc
                if 0 <= nr < H and 0 <= nc < W and grid[nr,nc] == v:
                    same_count += 1
            if same_count <= 1:
                initial[r, c] = True

    # Expand: BFS from initial defects to include adjacent candidates of same color
    defects = initial.copy()
    queue = deque(zip(*np.where(initial)))
    while queue:
        r, c = queue.popleft()
        v = grid[r, c]
        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
            nr, nc = r+dr, c+dc
            if 0 <= nr < H and 0 <= nc < W and not defects[nr, nc] and candidates[nr, nc] and grid[nr, nc] == v:
                defects[nr, nc] = True
                queue.append((nr, nc))

    # Step 2: Classify and transform
    output = grid.copy()

    # Find 0-defects and 1-defects
    zero_defects = defects & (grid == 0)  # 0s in 1-regions
    one_defects = defects & (grid == 1)   # 1s in 0-regions

    # Erase 1-defects
    output[one_defects] = 0

    # For 0-defects: add 7-border
    for r, c in zip(*np.where(zero_defects)):
        for dr in [-1, 0, 1]:
            for dc in [-1, 0, 1]:
                if dr == 0 and dc == 0:
                    continue
                nr, nc = r+dr, c+dc
                if 0 <= nr < H and 0 <= nc < W and not zero_defects[nr, nc]:
                    output[nr, nc] = 7

    return output.tolist()

